import{_ as t,a,b as n,c as d}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Thêm Yandex Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/yandex.md","filePath":"vi-VN/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"vi-VN/upload/yandex.md"};function c(p,e,h,u,b,m){return i(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="them-yandex-channel" tabindex="-1">Thêm Yandex Channel <a class="header-anchor" href="#them-yandex-channel" aria-label="Permalink to &quot;Thêm Yandex Channel&quot;">​</a></h1><h2 id="can-chuan-bi-truoc" tabindex="-1">Cần chuẩn bị trước <a class="header-anchor" href="#can-chuan-bi-truoc" aria-label="Permalink to &quot;Cần chuẩn bị trước&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Vì sao cần</th></tr></thead><tbody><tr><td>Yandex account</td><td>Dùng để sign in và authorize Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>Dùng để generate <code>Client ID</code> và <code>Client Secret</code></td></tr><tr><td>ImgBed domain của bạn</td><td>Dùng cho OAuth redirect URI</td></tr><tr><td>Available Yandex Disk storage</td><td>Dùng làm nơi lưu file thực tế</td></tr></tbody></table><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><h3 id="step-1-tao-yandex-oauth-app" tabindex="-1">Step 1: Tạo Yandex OAuth App <a class="header-anchor" href="#step-1-tao-yandex-oauth-app" aria-label="Permalink to &quot;Step 1: Tạo Yandex OAuth App&quot;">​</a></h3><ol><li>Mở trang tạo Yandex OAuth app:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Nếu bị redirect sang sign in, hãy sign in bằng Yandex account trước.</li><li>Tạo app mới.</li><li>Đặt tên app dễ nhận biết, ví dụ <code>imgbed-yandex</code>.</li><li>Tìm phần callback hoặc redirect URL settings.</li><li>Nhập:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-xac-nhan-permissions" tabindex="-1">Step 2: Xác nhận Permissions <a class="header-anchor" href="#step-2-xac-nhan-permissions" aria-label="Permalink to &quot;Step 2: Xác nhận Permissions&quot;">​</a></h3><p>Với ImgBed Yandex integration hiện tại, giữ bốn permissions này trong <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Cho phép ImgBed lưu files trong app folder</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Đọc files và download links</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Upload files, tạo folders và xóa files</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Đọc disk quota và used space</td></tr></tbody></table><p>Nếu cũng thấy các permissions này trong <code>Yandex ID API</code>, chúng là optional:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>Các tính năng upload, download, deletion và quota chủ yếu phụ thuộc vào bốn permissions <code>Yandex.Disk REST API</code> ở trên.</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-copy-app-credentials" tabindex="-1">Step 3: Copy App Credentials <a class="header-anchor" href="#step-3-copy-app-credentials" aria-label="Permalink to &quot;Step 3: Copy App Credentials&quot;">​</a></h3><p>Sau khi app được tạo, copy:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-đien-yandex-channel" tabindex="-1">Step 4: Điền Yandex Channel <a class="header-anchor" href="#step-4-đien-yandex-channel" aria-label="Permalink to &quot;Step 4: Điền Yandex Channel&quot;">​</a></h3><p>Trong Upload Settings, chọn <code>Yandex</code> và điền:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Nhập gì</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết, ví dụ <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>Tạm thời để trống</td></tr><tr><td>Root directory</td><td>Optional. Mặc định là <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-lay-refresh-token" tabindex="-1">Step 5: Lấy Refresh Token <a class="header-anchor" href="#step-5-lay-refresh-token" aria-label="Permalink to &quot;Step 5: Lấy Refresh Token&quot;">​</a></h3><ol><li>Trong ImgBed, nhấn <code>Get Token</code>.</li><li>Sign in vào Yandex account bạn muốn kết nối.</li><li>Approve authorization prompt.</li><li>Callback page sẽ hiển thị <code>Refresh Token</code>.</li><li>Copy token đó.</li><li>Quay lại ImgBed và paste vào field <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-save-channel" tabindex="-1">Step 6: Save Channel <a class="header-anchor" href="#step-6-save-channel" aria-label="Permalink to &quot;Step 6: Save Channel&quot;">​</a></h3><p>Sau khi điền đủ fields, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mở Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Tạo app</span></span>
<span class="line"><span>-&gt; Thêm https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Xác nhận Yandex Disk permissions</span></span>
<span class="line"><span>-&gt; Copy Client ID và Client Secret</span></span>
<span class="line"><span>-&gt; Điền Client ID / Client Secret vào ImgBed</span></span>
<span class="line"><span>-&gt; Nhấn Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token từ callback page</span></span>
<span class="line"><span>-&gt; Paste lại vào ImgBed và save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=o(r,[["render",c]]);export{k as __pageData,y as default};
